use std::fs;

fn main() {
    let data = fs::read("/home/coding/gribtract/tests/corpus/small/gfs_tmp2m_1deg_anl.grib2").unwrap();

    // Find Section 5 DRT=3 data to see what group widths are used
    let bytes = data;
    let mut pos = 0;

    while pos < bytes.len() - 4 {
        if &bytes[pos..pos+4] != b"GRIB" {
            break;
        }
        pos += 16; // Skip Section 0

        let body_end = {
            let len = u32::from_be_bytes([bytes[pos], bytes[pos+1], bytes[pos+2], bytes[pos+3]]) as usize;
            pos + len - 4
        };

        while pos < body_end {
            let sec_len = u32::from_be_bytes([bytes[pos], bytes[pos+1], bytes[pos+2], bytes[pos+3]]) as usize;
            let sec_num = bytes[pos + 4];

            if sec_num == 5 {
                // Check if DRT=3
                let drt = u16::from_be_bytes([bytes[pos + 10], bytes[pos + 11]]);
                if drt == 3 {
                    println!("Found DRT=3 field");
                    // Parse extra fields to get group widths
                    let n_groups = u32::from_be_bytes([bytes[pos + 32], bytes[pos + 33], bytes[pos + 34], bytes[pos + 35]]);
                    let ref_w = bytes[pos + 36];
                    let bits_w = bytes[pos + 37];

                    println!("  n_groups={}, ref_w={}, bits_w={}", n_groups, ref_w, bits_w);

                    // Calculate where widths start (after DRT=3 specific octets)
                    let widths_byte_pos = pos + 5 + 49; // Section 5 header + DRT=3 extra octets
                    let mut bit_pos = 0;

                    for g in 0..n_groups.min(20) {
                        let byte_pos = bit_pos / 8;
                        let bit_start = bit_pos % 8;
                        let mut raw: u64 = 0;
                        for i in 0..((bits_w as usize + bit_start + 7) / 8) {
                            let byte = bytes[widths_byte_pos + byte_pos + i] as u64;
                            raw = (raw << 8) | byte;
                        }
                        let total_bits = ((bits_w as usize + bit_start + 7) / 8) * 8;
                        let shift = total_bits - bit_start - bits_w as usize;
                        let w = (raw >> shift) & ((1u64 << bits_w) - 1);
                        println!("  Group {}: w={}", g, ref_w as u64 + w);
                        bit_pos += bits_w as usize;
                    }
                }
            }

            pos += sec_len;
        }
    }
}
